// src/components/ai/AITagGenerator.jsx
// Feature 3: AI reads post and suggests 5 relevant tags
import { useState } from "react";
import { generateTags } from "../../ai/aiService";

export default function AITagGenerator({ title, content, onTagsGenerated }) {
  const [tags, setTags]       = useState([]);
  const [loading, setLoading] = useState(false);
  const [selected, setSelected] = useState([]);
  const [error, setError]     = useState("");

  const handleGenerate = async () => {
    if (!title.trim() || !content.trim()) {
      setError("Add title and content first."); return;
    }
    setLoading(true); setError("");
    try {
      const result = await generateTags(title, content);
      setTags(result);
      setSelected(result); // auto-select all
      onTagsGenerated?.(result);
    } catch {
      setError("Could not generate tags.");
    }
    setLoading(false);
  };

  const toggleTag = (tag) => {
    const next = selected.includes(tag)
      ? selected.filter((t) => t !== tag)
      : [...selected, tag];
    setSelected(next);
    onTagsGenerated?.(next);
  };

  return (
    <div style={s.wrap}>
      <div style={s.header}>
        <span style={s.label}>🏷️ AI Tags</span>
        <button style={{ ...s.btn, opacity: loading ? 0.7 : 1 }}
          onClick={handleGenerate} disabled={loading}>
          {loading ? <><span style={s.spinner} /> Generating…</> : "✨ Auto-generate"}
        </button>
      </div>

      {error && <span style={s.error}>{error}</span>}

      {tags.length > 0 && (
        <div style={s.tagsRow}>
          {tags.map((tag) => (
            <button
              key={tag}
              style={{
                ...s.tag,
                background: selected.includes(tag) ? "#1d4ed8" : "var(--bg)",
                color: selected.includes(tag) ? "#fff" : "var(--mid)",
                borderColor: selected.includes(tag) ? "#1d4ed8" : "var(--border)",
              }}
              onClick={() => toggleTag(tag)}
            >
              #{tag}
            </button>
          ))}
          <span style={s.hint}>Click to toggle</span>
        </div>
      )}
    </div>
  );
}

const s = {
  wrap: {
    background: "var(--bg-2)", border: "1px solid var(--border)",
    borderRadius: 10, padding: "12px 14px", marginBottom: 4,
  },
  header: {
    display: "flex", alignItems: "center",
    justifyContent: "space-between", marginBottom: 10,
  },
  label: {
    fontFamily: "var(--font-display)", fontWeight: 800,
    fontSize: "0.83rem", color: "var(--ink)",
  },
  btn: {
    padding: "6px 12px", background: "#1d4ed8", color: "#fff",
    border: "none", borderRadius: 7,
    fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.76rem",
    cursor: "pointer", display: "flex", alignItems: "center", gap: 5,
  },
  spinner: {
    width: 12, height: 12, border: "2px solid rgba(255,255,255,0.3)",
    borderTopColor: "#fff", borderRadius: "50%",
    animation: "spin 0.7s linear infinite", display: "inline-block",
  },
  error: {
    fontSize: "0.76rem", color: "#dc2626",
    fontFamily: "var(--font-display)",
  },
  tagsRow: {
    display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center",
  },
  tag: {
    padding: "4px 12px", borderRadius: 100,
    border: "1.5px solid var(--border)",
    fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "0.76rem",
    cursor: "pointer", transition: "all 0.15s",
  },
  hint: {
    fontSize: "0.68rem", color: "var(--muted)",
    fontFamily: "var(--font-display)",
  },
};
